PRAGMA foreign_keys = ON;

CREATE TABLE project (
    project_id INTEGER PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE project_metrics (
    project_id INTEGER PRIMARY KEY REFERENCES project(project_id) ON DELETE CASCADE,
    open_ticket_count INTEGER NOT NULL DEFAULT 0 CHECK (open_ticket_count >= 0)
);

CREATE TABLE ticket (
    ticket_id INTEGER PRIMARY KEY,
    project_id INTEGER NOT NULL REFERENCES project(project_id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    due_on TEXT,
    archived_at TEXT
);

CREATE TRIGGER project_metrics_create
AFTER INSERT ON project
BEGIN
    INSERT INTO project_metrics(project_id, open_ticket_count)
    VALUES (NEW.project_id, 0);
END;

CREATE TRIGGER ticket_metrics_insert
AFTER INSERT ON ticket
BEGIN
    UPDATE project_metrics
       SET open_ticket_count = open_ticket_count +
           CASE WHEN NEW.archived_at IS NULL THEN 1 ELSE 0 END
     WHERE project_id = NEW.project_id;
END;

CREATE TRIGGER ticket_metrics_delete
AFTER DELETE ON ticket
BEGIN
    UPDATE project_metrics
       SET open_ticket_count = open_ticket_count -
           CASE WHEN OLD.archived_at IS NULL THEN 1 ELSE 0 END
     WHERE project_id = OLD.project_id;
END;

CREATE TRIGGER ticket_metrics_move
AFTER UPDATE OF project_id ON ticket
WHEN OLD.project_id <> NEW.project_id
BEGIN
    UPDATE project_metrics
       SET open_ticket_count = open_ticket_count - 1
     WHERE project_id = OLD.project_id;
    UPDATE project_metrics
       SET open_ticket_count = open_ticket_count + 1
     WHERE project_id = NEW.project_id;
END;
